     1→"use client";
     2→
     3→import React, { createContext, useContext, useState, useEffect } from "react";
     4→import { toast } from "sonner";
     5→import { useRouter } from "next/navigation";
     6→import { createClient } from "@/lib/supabase/client";
     7→import { User, Session } from "@supabase/supabase-js";
     8→
     9→interface AuthContextType {
    10→    user: User | null;
    11→    session: Session | null;
    12→    isLoading: boolean;
    13→    signIn: (email: string, password?: string) => Promise<void>;
    14→    signUp: (email: string, password?: string, data?: Record<string, unknown>) => Promise<void>;
    15→    signOut: () => Promise<void>;
    16→    showAuthModal: boolean;
    17→    setShowAuthModal: (show: boolean) => void;
    18→}
    19→
    20→const AuthContext = createContext<AuthContextType | undefined>(undefined);
    21→
    22→export function AuthProvider({ children }: { children: React.ReactNode }) {
    23→    const [user, setUser] = useState<User | null>(null);
    24→    const [session, setSession] = useState<Session | null>(null);
    25→    const [isLoading, setIsLoading] = useState(true);
    26→    const [showAuthModal, setShowAuthModal] = useState(false);
    27→    const router = useRouter();
    28→    const supabase = createClient();
    29→
    30→    // Initialize Auth State
    31→    useEffect(() => {
    32→        const initAuth = async () => {
    33→            try {
    34→                const { data: { session } } = await supabase.auth.getSession();
    35→                setSession(session);
    36→                setUser(session?.user ?? null);
    37→            } catch (error) {
    38→                console.error("Auth init error:", error);
    39→            } finally {
    40→                setIsLoading(false);
    41→            }
    42→        };
    43→
    44→        const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
    45→            setSession(session);
    46→            setUser(session?.user ?? null);
    47→            setIsLoading(false);
    48→
    49→            if (session) {
    50→                setShowAuthModal(false);
    51→
    52→                // Auto-create profile if it doesn't exist
    53→                const { data: existingProfile } = await supabase
    54→                    .from("profiles")
    55→                    .select("id")
    56→                    .eq("id", session.user.id)
    57→                    .single();
    58→
    59→                if (!existingProfile) {
    60→                    const meta = session.user.user_metadata;
    61→                    await supabase.from("profiles").insert({
    62→                        id: session.user.id,
    63→                        display_name: meta?.display_name || null,
    64→                        entity_type: meta?.entity_type || 'individual',
    65→                        lab_name: meta?.lab_name || null,
    66→                    }).then(({ error }) => {
    67→                        if (error && error.code !== '23505') {
    68→                            console.error("Profile auto-creation error:", error);
    69→                        }
    70→                    });
    71→                }
    72→            }
    73→        });
    74→
    75→        initAuth();
    76→
    77→        return () => subscription.unsubscribe();
    78→    }, [supabase]);
    79→
    80→    const signIn = async (email: string, password?: string) => {
    81→        try {
    82→            setIsLoading(true);
    83→
    84→            if (password) {
    85→                // Email + Password
    86→                const { error } = await supabase.auth.signInWithPassword({
    87→                    email,
    88→                    password
    89→                });
    90→                if (error) throw error;
    91→                toast.success("Bon retour", { description: "Connexion réussie." });
    92→            } else {
    93→                // Magic Link (Fallback)
    94→                const { error } = await supabase.auth.signInWithOtp({
    95→                    email,
    96→                    options: {
    97→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
    98→                    },
    99→                });
   100→                if (error) throw error;
   101→                toast.success("Lien de connexion envoyé", { description: "Vérifiez votre boîte mail." });
   102→            }
   103→            setShowAuthModal(false);
   104→        } catch (error: unknown) {
   105→            console.error("Login error:", error);
   106→            const message = error instanceof Error ? error.message : "Identifiants invalides.";
   107→            toast.error("Erreur de connexion", { description: message });
   108→        } finally {
   109→            setIsLoading(false);
   110→        }
   111→    };
   112→
   113→    const signUp = async (email: string, password?: string, data?: Record<string, unknown>) => {
   114→        try {
   115→            setIsLoading(true);
   116→
   117→            if (password) {
   118→                const { error } = await supabase.auth.signUp({
   119→                    email,
   120→                    password,
   121→                    options: {
   122→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
   123→                        data: data
   124→                    }
   125→                });
   126→                if (error) throw error;
   127→                toast.success("Compte créé", { description: "Vérifiez votre email pour confirmer." });
   128→            } else {
   129→                const { error } = await supabase.auth.signInWithOtp({
   130→                    email,
   131→                    options: {
   132→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
   133→                    }
   134→                });
   135→                if (error) throw error;
   136→                toast.success("Vérifiez votre email", { description: "Un lien de connexion a été envoyé." });
   137→            }
   138→            setShowAuthModal(false);
   139→        } catch (error: unknown) {
   140→            console.error("Signup error:", error);
   141→            const message = error instanceof Error ? error.message : "Une erreur est survenue";
   142→            toast.error("Erreur d'inscription", { description: message });
   143→        } finally {
   144→            setIsLoading(false);
   145→        }
   146→    };
   147→
   148→    const signOut = async () => {
   149→        try {
   150→            setIsLoading(true);
   151→            await supabase.auth.signOut();
   152→            toast.info("Déconnecté");
   153→            router.push("/");
   154→            router.refresh();
   155→        } catch (error) {
   156→            console.error("SignOut error:", error);
   157→        } finally {
   158→            setIsLoading(false);
   159→        }
   160→    };
   161→
   162→    return (
   163→        <AuthContext.Provider value={{
   164→            user,
   165→            session,
   166→            isLoading,
   167→            signIn,
   168→            signUp,
   169→            signOut,
   170→            showAuthModal,
   171→            setShowAuthModal
   172→        }}>
   173→            {children}
   174→        </AuthContext.Provider>
   175→    );
   176→}
   177→
   178→export function useAuth() {
   179→    const context = useContext(AuthContext);
   180→    if (context === undefined) {
   181→        throw new Error("useAuth must be used within an AuthProvider");
   182→    }
   183→    return context;
   184→}
